import elasticsearch
from elasticsearch import Elasticsearch

es = Elasticsearch(["http://localhost:9200"])

# Document indexing
doc = {"title": "Awesome Python", "text": "Python is a great programming language"}
es.index(index="my_index", id=1, body=doc)

# Search queries
query = {
    "query": {
        "match": {
            "text": "great"
        }
    }
}
results = es.search(index="my_index", body=query)
print(results["hits"]["hits"])

# Log aggregation features
log = {"message": "This is a log message"}
es.index(index="my_logs", id=1, body=log)